            sh:resultPath schema1:datePublished ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:datePublishedProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <http://n2t.net/ark:/23942/g2example-dataset> ;
            sh:resultMessage "provide identifiers for specifications used in this record to provide guidance for machine agents processing the metadata record" ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:metadataProfileProperty ] .

